        // Hàm áp dụng bản dịch cho tất cả các text node tĩnh trên trang
        function applyStaticTranslations() {
            if (translations[document.title]) {
                document.title = translations[document.title];
            }

            // **SỬA LỖI: Thêm .et-n vào danh sách selector để dịch tên nhân vật ở tab 2**
            const elements = document.querySelectorAll("button, .sp-title, .et-h, .sp-l, .sp-sl, .et-l, .time-display, .et-v, .sp-n, .et-n");

            elements.forEach(el => {
                const childNodes = [...el.childNodes];
                childNodes.forEach(node => {
                    if (node.nodeType === Node.TEXT_NODE) {
                        let translatedText = node.nodeValue;
                        const sortedKeys = Object.keys(translations).sort((a, b) => b.length - a.length);
                        sortedKeys.forEach(key => {
                            const regex = new RegExp(key.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&'), 'g');
                            translatedText = translatedText.replace(regex, translations[key]);
                        });
                        node.nodeValue = translatedText;
                    }
                });
            });
        }
