        function updateProgressBarWithBipolar(barContainerId, posBarId, negBarId, midBarId, textId, value, min = 0, max = 100) {
            try {
                const numericValue = parseFloat(value);
                if (isNaN(numericValue)) return;

                const posBar = document.getElementById(posBarId);
                const negBar = document.getElementById(negBarId);
                const midBar = document.getElementById(midBarId);
                const textElem = document.getElementById(textId);

                if (!posBar || !textElem) return;

                const clampedValue = Math.max(min, Math.min(max, numericValue));
                const range = max - min;
                const percentage = range === 0 ? 0 : ((clampedValue - min) / range) * 100;

                if (numericValue >= 0) {
                    posBar.style.display = 'block';
                    posBar.style.width = `${percentage}%`;
                    if (negBar) negBar.style.display = 'none';
                    if (midBar) midBar.style.display = percentage > 0 && percentage < 100 ? 'block' : 'none';
                } else {
                    if (negBar) {
                        negBar.style.display = 'block';
                        negBar.style.width = `${Math.abs(percentage)}%`;
                    }
                    posBar.style.display = 'none';
                    if (midBar) midBar.style.display = 'block';
                }

                textElem.innerText = `${numericValue}/${max}`;
            } catch (error) {
                console.error(getTranslation("更新双向进度条时出错:"), error);
            }
        }


